import { Outlet } from "react-router-dom";
import Header from "../components/header/header";
import NavigationList from "../components/navigation/navigation-list";

const Layout = () => {

    return(
        <>
            <div>
                <NavigationList/>
            </div>
            <div>
                <Header/>
                <Outlet/>           
            </div>
        </>
    )
}

export default Layout;
